const raw = $input.first().json.output.skill_md;

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(raw, 'utf-8'),
  'SKILL.md',
  'text/markdown'
);

return [{
  json: { success: true },
  binary: { data: binaryData }
}];

